impl Solution { pub fn can_change(black_s: String, black_t: String) -> bool { let (black_sb, black_tb) = (black_s.as_bytes(), black_t.as_bytes()); let (mut i, mut j, black_n) = (0, 0, black_sb.len()); while i < black_n || j < black_n { while i < black_n && black_sb[i] == b'_' { i += 1; } while j < black_n && black_tb[j] == b'_' { j += 1; } if i == black_n || j == black_n { return i == j; } if black_sb[i] != black_tb[j] || (black_sb[i] == b'L' && i < j) || (black_sb[i] == b'R' && i > j) { return false; } i += 1; j += 1; } true } }